# BEST PRACTICE: Routing + Caching Pattern
import anthropic
from functools import lru_cache

client = anthropic.Anthropic()

# System prompt cached at API level
BATSMAN_CONTEXT = """
You are a cricket analytics expert. Analyze batter statistics and recommend strategies.
"""

def route_query(query: str) -> str:
    """Route to appropriate model based on complexity."""
    if len(query.split()) < 10:
        return "fast-track"  # Simple queries use cheaper model
    elif "historical" in query.lower() or "trend" in query.lower():
        return "rag-required"  # Complex analysis needs RAG
    return "standard"

def analyze_batsman(player_name: str, query: str) -> dict:
    """Production-ready with routing and caching."""
    route = route_query(query)

    # Simulated cached player data
    cached_stats = {"virat_kohli": {"avg": 51.2, "sr": 93.5}}
    player_data = cached_stats.get(player_name.lower(), {})

    if route == "fast-track":
        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=200,
            system=BATSMAN_CONTEXT,
            messages=[{
                "role": "user",
                "content": f"Quick analysis: {query}. Data: {player_data}"
            }]
        )
    else:
        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1000,
            system=BATSMAN_CONTEXT,
            messages=[{
                "role": "user",
                "content": f"Detailed analysis: {query}. Full context: {player_data}"
            }]
        )

    return {
        "route_used": route,
        "response": response.content[0].text,
        "tokens_used": response.usage.output_tokens
    }

# ANTI-PATTERN: No routing, no caching
def analyze_batsman_bad(player_name: str, query: str) -> str:
    """Inefficient - sends every query to largest model."""
    response = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=2000,
        messages=[{
            "role": "user",
            "content": f"Please analyze {player_name}: {query}"
        }]
    )
    # No caching, no routing = 3-5x higher cost and latency
    return response.content[0].text

# Usage comparison
print(analyze_batsman("virat_kohli", "Avg vs pace?"))  # ~150 tokens, routed
print(analyze_batsman_bad("virat_kohli", "Avg vs pace?"))  # ~800 tokens, no routing

# Production-ready LLM system example (simplified)
import logging
from datetime import datetime
from typing import Optional

class CricketCommentaryLLMSystem:
    def __init__(self, model_name: str, fallback_model: str):
        self.primary_model = model_name
        self.fallback_model = fallback_model
        self.request_log = []
        self.cost_tracker = {"tokens_used": 0, "cost_usd": 0.0}

    def generate_match_commentary(self, 
                                  match_state: dict,
                                  max_tokens: int = 150,
                                  temperature: float = 0.7) -> dict:
        """Production-ready commentary generation with guardrails."""

        request_id = f"commentary_{datetime.now().timestamp()}"

        try:
            # 1. Validate input (guardrails)
            if not self._validate_match_state(match_state):
                return {"error": "Invalid match state", "request_id": request_id}

            # 2. Build context-aware prompt (context window management)
            innings_summary = match_state.get("recent_overs", [])[-10:]  # Last 10 overs
            prompt = self._build_context_prompt(innings_summary, match_state)

            # 3. Call primary model with token budget
            response = self._call_model(
                model=self.primary_model,
                prompt=prompt,
                max_tokens=max_tokens,
                temperature=temperature
            )

            # 4. Validate output (quality gates)
            if not self._validate_output(response):
                logging.warning(f"Output validation failed for {request_id}")
                response = self._call_model(
                    model=self.fallback_model,
                    prompt=prompt,
                    max_tokens=max_tokens
                )

            # 5. Log and track (observability)
            self._log_request(request_id, response, match_state)
            self._track_cost(response.get("tokens_used", 0))

            return {
                "commentary": response.get("text", ""),
                "request_id": request_id,
                "tokens_used": response.get("tokens_used", 0),
                "model_used": response.get("model", self.primary_model)
            }

        except Exception as e:
            logging.error(f"System failure for {request_id}: {str(e)}")
            return {"error": "System unavailable", "request_id": request_id}

    def _build_context_prompt(self, recent_overs: list, match_state: dict) -> str:
        """RAG-style context integration."""
        context = f"""Batting team: {match_state['batting_team']}
        Score: {match_state['runs']}/{match_state['wickets']} ({match_state['overs']} overs)
        Recent overs: {', '.join(recent_overs)}
        Next batter: {match_state.get('next_batter', 'Unknown')}"""

        return f"Generate cricket commentary for: {context}"

    def _validate_match_state(self, state: dict) -> bool:
        required_fields = ['batting_team', 'runs', 'wickets', 'overs']
        return all(field in state for field in required_fields)

    def _validate_output(self, response: dict) -> bool:
        text = response.get("text", "")
        # Check for hallucinations (impossible scores, etc.)
        if "9999" in text or len(text) < 20 or len(text) > 500:
            return False
        return True

    def _call_model(self, model: str, prompt: str, max_tokens: int, 
                    temperature: float = 0.7) -> dict:
        # Simulated API call
        logging.info(f"Calling {model} with {len(prompt)} chars, max_tokens={max_tokens}")
        return {"text": f"Commentary for {prompt[:50]}...", 
                "tokens_used": 120,
                "model": model}

    def _log_request(self, request_id: str, response: dict, state: dict):
        log_entry = {
            "timestamp": datetime.now().isoformat(),
            "request_id": request_id,
            "tokens": response.get("tokens_used", 0),
            "model": response.get("model")
        }
        self.request_log.append(log_entry)

    def _track_cost(self, tokens: int, cost_per_1k_tokens: float = 0.002):
        self.cost_tracker["tokens_used"] += tokens
        self.cost_tracker["cost_usd"] += (tokens / 1000) * cost_per_1k_tokens

        # Alert if daily cost exceeds threshold
        if self.cost_tracker["cost_usd"] > 100:
            logging.warning(f"Daily cost approaching limit: ${self.cost_tracker['cost_usd']:.2f}")
